// Récupère les données du webhook (body peut être à la racine ou dans .body)
const webhookData = $('Webhook Upload').first().json
const body = webhookData.body || webhookData
const case_id = body.case_id || null
const doc_id = body.doc_id || null

// Récupère la réponse Groq
const raw = $input.first().json?.choices?.[0]?.message?.content || ''

let summary = null
let extracted_date = null
let doc_type = null

try {
  // Nettoie le markdown si Groq en ajoute
  const cleaned = raw
    .replace(/^```json\s*/i, '')
    .replace(/^```\s*/i, '')
    .replace(/```\s*$/i, '')
    .trim()
  const o = JSON.parse(cleaned)
  summary = typeof o.summary === 'string' ? o.summary : null
  // Valide le format de date
  if (o.extracted_date && /^\d{4}-\d{2}-\d{2}$/.test(o.extracted_date)) {
    extracted_date = o.extracted_date
  }
  doc_type = typeof o.doc_type === 'string' ? o.doc_type : null
} catch (e) {
  // Si parse échoue, met le texte brut comme summary
  summary = raw.slice(0, 500) || 'Extraction automatique'
}

return [{ json: { case_id, doc_id, summary, extracted_date, doc_type } }]
